import{_ as s,o as a,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"CAT-16. 크리에이티브 & 콘텐츠","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/creative-content.md","filePath":"hermes/benchmark/creative-content.md","lastUpdated":1781092690000}'),e={name:"hermes/benchmark/creative-content.md"};function i(c,n,t,o,r,u){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="cat-16-크리에이티브-콘텐츠" tabindex="-1">CAT-16. 크리에이티브 &amp; 콘텐츠 <a class="header-anchor" href="#cat-16-크리에이티브-콘텐츠" aria-label="Permalink to &quot;CAT-16. 크리에이티브 &amp; 콘텐츠&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 뉴스레터, 영상 기획, 카피라이팅, 스토리텔링 등 <strong>창의적 콘텐츠 제작</strong>을 할 수 있는가?</p></blockquote><hr><h2 id="cc-01-사내-뉴스레터-제작" tabindex="-1">CC-01. 사내 뉴스레터 제작 ⭐⭐ <a class="header-anchor" href="#cc-01-사내-뉴스레터-제작" aria-label="Permalink to &quot;CC-01. 사내 뉴스레터 제작 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>매주/매월 발행하는 사내 뉴스레터. 직원들이 실제로 읽게 만드는 것이 핵심.</p><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사내 월간 뉴스레터 4월호를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: IT 기업 &quot;넥스트웨어&quot; (직원 150명)</span></span>
<span class="line"><span>뉴스레터명: &quot;넥스트레터&quot;</span></span>
<span class="line"><span>발행: 매월 첫째 주 월요일, 전사 이메일 발송</span></span>
<span class="line"><span>현재 오픈율: 35% (목표 60%)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4월 소재:</span></span>
<span class="line"><span>- 회사 뉴스: Q1 매출 목표 초과 달성 (109%), 신규 대형 고객 2사 계약</span></span>
<span class="line"><span>- 인사: 신규 입사자 5명 소개, 3월 우수사원 (개발팀 이현정)</span></span>
<span class="line"><span>- 프로젝트: &quot;스마트팩토리&quot; 프로젝트 성공적 1차 오픈</span></span>
<span class="line"><span>- 행사: 4/20 가족 초청 행사, 4/25 봄 워크숍</span></span>
<span class="line"><span>- 복지: 5월부터 자기개발비 한도 상향 (50→100만원)</span></span>
<span class="line"><span>- 가벼운 콘텐츠: 사내 맛집 추천 (회사 근처 점심), 이달의 playlist</span></span>
<span class="line"><span></span></span>
<span class="line"><span>뉴스레터 구성:</span></span>
<span class="line"><span>1. 편집장 인사 (대표 또는 HR) — 3~4줄, 시즌 감성</span></span>
<span class="line"><span>2. 이번 달 하이라이트 (Q1 실적) — 숫자 강조, 축하 톤</span></span>
<span class="line"><span>3. Welcome! 신규 입사자 소개 — 이름, 소속, 한 줄 자기소개, 취미</span></span>
<span class="line"><span>4. 프로젝트 스포트라이트 — 스마트팩토리 프로젝트 스토리</span></span>
<span class="line"><span>5. 이달의 우수사원 — 선정 이유, 동료 코멘트 (가상)</span></span>
<span class="line"><span>6. 다가오는 행사 — 캘린더 형식</span></span>
<span class="line"><span>7. 알림 (자기개발비 상향) — 핵심만 간결하게</span></span>
<span class="line"><span>8. 가벼운 코너 — 맛집 3곳 + 직원 투표 결과(가상)</span></span>
<span class="line"><span>9. 에디터 클로징 — 다음 호 예고</span></span>
<span class="line"><span></span></span>
<span class="line"><span>톤: 뉴스 보도 아님. 친한 동료가 알려주는 느낌.</span></span>
<span class="line"><span>형식: HTML 이메일 기준 마크다운으로 작성.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`content/newsletter-april-2024.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>주의: </span></span>
<span class="line"><span>- 오픈율 35%인 이유는 지루하기 때문. 재미 요소 필수.</span></span>
<span class="line"><span>- 이모지 적절히 사용 OK (과하지 않게)</span></span>
<span class="line"><span>- &quot;회사가 잘되고 있다&quot;를 강조하되 자화자찬은 금물</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 전체 구성의 리듬감 (무거운↔가벼운 교차)</li><li>[ ] 편집장 인사의 시즌 감성</li><li>[ ] 신규 입사자 소개의 개인적 느낌</li><li>[ ] 프로젝트 스토리텔링 (프로젝트 수행기 형태)</li><li>[ ] 가벼운 코너의 재미 요소</li><li>[ ] 오픈율 60% 달성에 기여할 만한 제목(subject line)</li><li>[ ] 적절한 이모지 사용량</li></ul><hr><h2 id="cc-02-영상-콘텐츠-기획안" tabindex="-1">CC-02. 영상 콘텐츠 기획안 ⭐⭐⭐ <a class="header-anchor" href="#cc-02-영상-콘텐츠-기획안" aria-label="Permalink to &quot;CC-02. 영상 콘텐츠 기획안 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-1" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-1" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>유튜브/인스타 릴스용 영상 기획. 촬영팀에게 전달할 기획서.</p><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>회사 유튜브 채널의 영상 시리즈 기획안을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>채널: HR SaaS 기업 &quot;피플웍스&quot; 공식 유튜브</span></span>
<span class="line"><span>구독자: 1,200명 (6개월 목표: 5,000명)</span></span>
<span class="line"><span>타깃 시청자: 중소기업 HR 담당자 + 스타트업 대표</span></span>
<span class="line"><span>목적: 브랜드 인지도 + 리드 생성</span></span>
<span class="line"><span></span></span>
<span class="line"><span>시리즈 기획:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`content/youtube-series-plan.md\` — 시리즈 전체 기획</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   시리즈명: &quot;HR 디버깅&quot; (HR 문제를 코드 디버깅하듯 해결)</span></span>
<span class="line"><span>   콘셉트: 중소기업이 겪는 HR 난제를 실용적으로 풀어주는 시리즈</span></span>
<span class="line"><span>   에피소드 수: 시즌 1 — 8편</span></span>
<span class="line"><span>   영상 길이: 8~12분</span></span>
<span class="line"><span>   촬영: 사내 스튜디오, 진행자 1명 (HR 매니저)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   에피소드 목록:</span></span>
<span class="line"><span>   EP01. &quot;퇴사자가 연쇄로 나올 때 — 이탈 패턴 읽기&quot;</span></span>
<span class="line"><span>   EP02. &quot;면접에서 좋았는데 입사하면 달라요 — 채용 미스매치 줄이기&quot;</span></span>
<span class="line"><span>   EP03. &quot;연봉 협상 요청이 왔을 때 — 보상 정책 설계 가이드&quot;</span></span>
<span class="line"><span>   EP04. &quot;팀장이 되긴 했는데 뭘 해야 하지 — 신임 매니저 서바이벌&quot;</span></span>
<span class="line"><span>   EP05. &quot;인사평가 시즌이 또 왔다 — 덜 고통스러운 평가법&quot;</span></span>
<span class="line"><span>   EP06. &quot;재택이요? 출근이요? — 하이브리드 근무 정책 만들기&quot;</span></span>
<span class="line"><span>   EP07. &quot;직원이 10명 → 50명 될 때 — 조직 구조 설계&quot;</span></span>
<span class="line"><span>   EP08. &quot;HR 담당자가 번아웃일 때 — HR의 HR&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. EP01 상세 기획서</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 기본 정보</span></span>
<span class="line"><span>   - 제목, 길이, 태그, 썸네일 콘셉트</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   B. 구성 (시간별)</span></span>
<span class="line"><span>   - 0:00~0:30 — 후킹 (충격적 통계 or 상황 재연)</span></span>
<span class="line"><span>   - 0:30~2:00 — 문제 정의 (&quot;연쇄 퇴사가 뭔지&quot;)</span></span>
<span class="line"><span>   - 2:00~5:00 — 원인 분석 (3가지 패턴)</span></span>
<span class="line"><span>   - 5:00~8:00 — 해결 방법 (실전 가이드)</span></span>
<span class="line"><span>   - 8:00~9:00 — 체크리스트 정리</span></span>
<span class="line"><span>   - 9:00~9:30 — CTA (&quot;구독/좋아요 + 다음 편 예고&quot;)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   C. 스크립트 (전체 대사)</span></span>
<span class="line"><span>   - 진행자 대사 전문</span></span>
<span class="line"><span>   - 화면에 보여줄 자막/인포그래픽 지시</span></span>
<span class="line"><span>   - B-roll 촬영 지시 (사무실 풍경, 빈 자리 등)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   D. 썸네일 &amp; 제목 A/B 테스트</span></span>
<span class="line"><span>   - 제목 3안 + 썸네일 콘셉트 3안</span></span>
<span class="line"><span>   - 클릭률 높은 요소 분석</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   E. SEO</span></span>
<span class="line"><span>   - 타깃 키워드 5개</span></span>
<span class="line"><span>   - 영상 설명문 (SEO 최적화)</span></span>
<span class="line"><span>   - 태그 목록</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`content/youtube-series-plan.md\`</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 8편 에피소드의 주제 선정 (실제 HR 고민 반영)</li><li>[ ] EP01 구성의 시간 배분 (후킹→본론→CTA)</li><li>[ ] 스크립트의 대화체 자연스러움</li><li>[ ] B-roll 촬영 지시의 구체성</li><li>[ ] 썸네일/제목 A/B안의 클릭 유도력</li><li>[ ] SEO 키워드의 적절성</li><li>[ ] 전체적으로 &quot;구독하고 싶은&quot; 시리즈인지</li></ul><hr><h2 id="cc-03-카피라이팅-실전" tabindex="-1">CC-03. 카피라이팅 실전 ⭐⭐ <a class="header-anchor" href="#cc-03-카피라이팅-실전" aria-label="Permalink to &quot;CC-03. 카피라이팅 실전 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-2" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-2" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>다양한 맥락의 카피를 짧은 시간에 대량으로 생성하는 능력.</p><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 상황별로 카피를 작성해줘. 총 30개.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>브랜드: &quot;릴랙스&quot; — 수면 보조 앱 (명상, 수면 음악, 수면 추적)</span></span>
<span class="line"><span>타깃: 25~45세, 수면에 문제를 느끼는 직장인</span></span>
<span class="line"><span>톤: 차분하고 따뜻한, 압박 없는</span></span>
<span class="line"><span></span></span>
<span class="line"><span>카피 유형:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A. 앱스토어 설명 (3개)</span></span>
<span class="line"><span>- 앱 이름 옆에 나오는 한 줄 설명 (15자 이내)</span></span>
<span class="line"><span>- 상세 설명 첫 3줄 (다운로드 결정적 영향)</span></span>
<span class="line"><span>- &quot;새로운 기능&quot; 업데이트 노트 (수면 리포트 기능 추가)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>B. 푸시 알림 (5개)</span></span>
<span class="line"><span>- 저녁 9시 수면 루틴 리마인더</span></span>
<span class="line"><span>- 7일 연속 사용 축하</span></span>
<span class="line"><span>- 30일 미접속 재활성화</span></span>
<span class="line"><span>- 새 명상 콘텐츠 추가 알림</span></span>
<span class="line"><span>- 수면 분석 리포트 준비 완료</span></span>
<span class="line"><span></span></span>
<span class="line"><span>C. 인앱 팝업 (4개)</span></span>
<span class="line"><span>- 무료→유료 전환 유도 (체험 종료 3일 전)</span></span>
<span class="line"><span>- 리뷰 요청 (5일 연속 사용 후)</span></span>
<span class="line"><span>- 친구 추천 이벤트</span></span>
<span class="line"><span>- 연간 구독 할인 프로모션 (40% off)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>D. 인스타그램 캡션 (5개)</span></span>
<span class="line"><span>- 월요일: 한 주 시작 응원</span></span>
<span class="line"><span>- 수요일: 수면 팁 (블루라이트 관련)</span></span>
<span class="line"><span>- 금요일: 주말 릴랙스 루틴 제안</span></span>
<span class="line"><span>- 시즌: 벚꽃 시즌 수면 명상</span></span>
<span class="line"><span>- 유저 후기 리그램 캡션</span></span>
<span class="line"><span></span></span>
<span class="line"><span>E. 이메일 제목줄 (8개)</span></span>
<span class="line"><span>- 가입 환영</span></span>
<span class="line"><span>- 사용 가이드</span></span>
<span class="line"><span>- 비활성 사용자 재참여</span></span>
<span class="line"><span>- 유료 전환 유도</span></span>
<span class="line"><span>- 할인 프로모션</span></span>
<span class="line"><span>- 수면 분석 리포트 발송</span></span>
<span class="line"><span>- 새해 특별 캠페인</span></span>
<span class="line"><span>- 해지 방지 (마지막 설득)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>F. 광고 카피 (5개)</span></span>
<span class="line"><span>- Google 검색 광고 (제목 30자 + 설명 90자)</span></span>
<span class="line"><span>- 인스타 피드 광고 (본문 + CTA)</span></span>
<span class="line"><span>- 유튜브 범퍼 광고 (6초 대사)</span></span>
<span class="line"><span>- 카카오 비즈보드 (한 줄 카피)</span></span>
<span class="line"><span>- 네이버 배너 (헤드라인 + 서브)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>모든 카피에:</span></span>
<span class="line"><span>- 왜 이렇게 썼는지 한 줄 의도 설명</span></span>
<span class="line"><span>- 대안 카피 1개씩 (A/B 테스트용)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`content/relax-copywriting-collection.md\`</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 30개 카피의 톤 일관성 (차분하고 따뜻한)</li><li>[ ] 채널별 길이/형식 준수 (푸시 알림 ≠ 이메일 ≠ 광고)</li><li>[ ] 전환 유도 카피의 설득력 (압박 없이)</li><li>[ ] 재활성화 카피의 공감 (죄책감 유발 안 함)</li><li>[ ] 유튜브 6초 범퍼 대사의 임팩트</li><li>[ ] A/B 대안의 차별화</li><li>[ ] 의도 설명의 마케팅 논리</li></ul><hr><h2 id="cc-04-기업-블로그-콘텐츠-전략" tabindex="-1">CC-04. 기업 블로그 콘텐츠 전략 ⭐⭐ <a class="header-anchor" href="#cc-04-기업-블로그-콘텐츠-전략" aria-label="Permalink to &quot;CC-04. 기업 블로그 콘텐츠 전략 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-3" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-3" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>SEO와 리드 생성을 고려한 블로그 콘텐츠 전략.</p><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B2B SaaS 기업의 블로그 콘텐츠 전략을 수립하고 샘플 포스트를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: &quot;체크메이트&quot; — 법인카드 경비 관리 SaaS</span></span>
<span class="line"><span>타깃: 중소기업 재무/총무 담당자, CFO</span></span>
<span class="line"><span>현재: 블로그 없음, SEO 유입 0</span></span>
<span class="line"><span>목표: 6개월 내 월 5,000 세션, 리드 50건/월</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`content/blog-content-strategy.md\` — 콘텐츠 전략</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   A. 키워드 리서치 (가상 데이터)</span></span>
<span class="line"><span>   - 타깃 키워드 30개 (검색량, 경쟁 강도, 의도)</span></span>
<span class="line"><span>   - 키워드 클러스터 5개 (주제별 그룹)</span></span>
<span class="line"><span>   - 우선순위 (검색량 × 전환 가능성 × 경쟁 강도)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   B. 콘텐츠 퍼널</span></span>
<span class="line"><span>   - TOFU (인지): &quot;법인카드 관리 방법&quot;, &quot;경비 정산 팁&quot;</span></span>
<span class="line"><span>   - MOFU (고려): &quot;경비 관리 SaaS 비교&quot;, &quot;엑셀 vs 전용 툴&quot;</span></span>
<span class="line"><span>   - BOFU (결정): 고객 사례, 제품 비교, 무료 체험 안내</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   C. 편집 캘린더 (6개월)</span></span>
<span class="line"><span>   - 월 4개 포스트 (총 24개)</span></span>
<span class="line"><span>   - 주제, 키워드, 퍼널 단계, 예상 발행일</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   D. 콘텐츠 가이드라인</span></span>
<span class="line"><span>   - 톤, 구조, 길이 (2,000~3,000자)</span></span>
<span class="line"><span>   - SEO 체크리스트 (제목, 메타, H2, 내부링크)</span></span>
<span class="line"><span>   - CTA 삽입 규칙</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`content/blog-sample-post.md\` — 샘플 포스트 1편</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   제목: &quot;법인카드 정산, 아직도 엑셀로 하세요? — 5가지 대안 비교&quot;</span></span>
<span class="line"><span>   - 키워드: &quot;법인카드 정산&quot;</span></span>
<span class="line"><span>   - 퍼널: MOFU</span></span>
<span class="line"><span>   - 길이: 약 2,500자</span></span>
<span class="line"><span>   - 구성: 도입(공감) → 현재 방식의 문제 → 5가지 대안 비교표 → </span></span>
<span class="line"><span>     선택 가이드 → CTA (무료 체험)</span></span>
<span class="line"><span>   - SEO 요소 모두 포함 (H1, H2, 메타 설명, ALT 텍스트 위치)</span></span>
<span class="line"><span>   - 마지막에 SEO 체크리스트 점검 결과</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 키워드 리서치의 현실성 (실제 검색될 법한)</li><li>[ ] TOFU/MOFU/BOFU 퍼널 분류의 정확성</li><li>[ ] 편집 캘린더의 주제 다양성</li><li>[ ] 샘플 포스트의 SEO 최적화 수준</li><li>[ ] 비교표의 공정성 (자사 편향 최소화)</li><li>[ ] CTA 삽입의 자연스러움</li><li>[ ] 전체적으로 &quot;읽히는&quot; 글인지</li></ul><hr><h2 id="cc-05-위기-커뮤니케이션-시나리오" tabindex="-1">CC-05. 위기 커뮤니케이션 시나리오 ⭐⭐⭐ <a class="header-anchor" href="#cc-05-위기-커뮤니케이션-시나리오" aria-label="Permalink to &quot;CC-05. 위기 커뮤니케이션 시나리오 :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-4" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-4" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>PR 위기 상황에서의 대외 커뮤니케이션. 한 번의 실수가 브랜드를 망칠 수 있는 상황.</p><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 위기 상황에 대한 커뮤니케이션 계획을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황:</span></span>
<span class="line"><span>- 우리: 건강식품 이커머스 &quot;내추럴라이프&quot;</span></span>
<span class="line"><span>- 사건: 판매한 유기농 주스에서 이물질(금속 파편) 발견</span></span>
<span class="line"><span>- 경위: 고객 1명이 음용 중 발견 → SNS에 사진 올림 → 2시간 만에 조회 5만</span></span>
<span class="line"><span>- 현재 상태: 해당 상품 200병 판매됨, 다른 피해 신고 아직 없음</span></span>
<span class="line"><span>- 원인: 아직 조사 중 (제조사 OEM, 우리는 유통)</span></span>
<span class="line"><span>- 시간: 지금 오후 3시, SNS 반응이 실시간으로 커지고 있음</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`content/crisis-communication-plan.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   A. 즉시 대응 (오후 3시~6시)</span></span>
<span class="line"><span>   - 내부 비상 회의 소집 (누가, 어디서)</span></span>
<span class="line"><span>   - 팩트 확인 체크리스트 (지금 확인할 수 있는 것)</span></span>
<span class="line"><span>   - SNS 1차 공식 대응 (30분 내 게시)</span></span>
<span class="line"><span>     - 게시할 내용 (인지+조사중+고객 안전 최우선)</span></span>
<span class="line"><span>     - 게시하면 안 되는 내용 (원인 추측, 책임 회피)</span></span>
<span class="line"><span>   - 고객 연락 (피해 고객 직접 연락, 통화 스크립트)</span></span>
<span class="line"><span>   - 해당 상품 즉시 판매 중지</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   B. D+1 대응</span></span>
<span class="line"><span>   - 공식 사과문 (홈페이지 + 이메일 + SNS)</span></span>
<span class="line"><span>   - 전량 리콜 공지 (환불 절차)</span></span>
<span class="line"><span>   - 언론 대응 (보도자료 or 기자 문의 Q&amp;A)</span></span>
<span class="line"><span>   - 식약처 신고 (자진 신고)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   C. D+3~7 대응</span></span>
<span class="line"><span>   - 원인 조사 결과 공유 (투명하게)</span></span>
<span class="line"><span>   - 재발 방지 대책 발표</span></span>
<span class="line"><span>   - 피해 고객 보상안 (환불 + α)</span></span>
<span class="line"><span>   - 신뢰 회복 캠페인 (품질 검사 과정 공개)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`content/crisis-templates.md\` — 템플릿 모음</span></span>
<span class="line"><span>   - SNS 1차 대응문 (인스타/트위터/페이스북 각각)</span></span>
<span class="line"><span>   - 공식 사과문 (홈페이지 게시용)</span></span>
<span class="line"><span>   - 고객 이메일 (구매자 전체)</span></span>
<span class="line"><span>   - 보도자료</span></span>
<span class="line"><span>   - 내부 직원 공지 (직원이 외부에서 질문받을 때 대응 가이드)</span></span>
<span class="line"><span>   - 고객 전화 문의 응대 스크립트</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`content/crisis-do-dont.md\` — 위기 대응 절대 원칙</span></span>
<span class="line"><span>   - DO: 빠른 인정, 투명한 공유, 고객 안전 최우선</span></span>
<span class="line"><span>   - DON&#39;T: 삭제/은폐, 책임 전가(&quot;제조사 잘못&quot;), 침묵, 법적 대응 위협</span></span>
<span class="line"><span>   - 소셜 미디어에서 절대 하면 안 되는 행동 5가지</span></span>
<span class="line"><span>   - 과거 기업 위기 대응 사례 (잘한 것 / 못한 것)</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 시간순 대응의 현실성 (30분 내 1차 대응)</li><li>[ ] SNS 1차 대응문의 톤 (인정+조사중, 변명 없이)</li><li>[ ] &quot;제조사 OEM&quot;임에도 책임 회피 안 하는 태도</li><li>[ ] 식약처 자진 신고의 포함 여부</li><li>[ ] 내부 직원 가이드의 실용성</li><li>[ ] 전량 리콜의 결단력 있는 제안</li><li>[ ] DO/DON&#39;T 리스트의 현실적 교훈</li></ul><hr><h2 id="cc-06-연간-보고서-annual-report" tabindex="-1">CC-06. 연간 보고서 (Annual Report) ⭐⭐⭐ <a class="header-anchor" href="#cc-06-연간-보고서-annual-report" aria-label="Permalink to &quot;CC-06. 연간 보고서 (Annual Report) :star::star::star:&quot;">​</a></h2><h3 id="시나리오-배경-5" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-5" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>이해관계자(투자자, 고객, 직원)에게 보여줄 연간 보고서.</p><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>스타트업의 2023년 연간 보고서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: &quot;그린웨이&quot; — 전기차 충전 인프라 스타트업</span></span>
<span class="line"><span>- 설립: 2021년</span></span>
<span class="line"><span>- 직원: 85명 (전년 55명)</span></span>
<span class="line"><span>- 매출: 120억원 (전년 45억, +167%)</span></span>
<span class="line"><span>- 충전소: 전국 500기 (전년 180기)</span></span>
<span class="line"><span>- 시리즈 B: 200억원 유치 (2023년 6월)</span></span>
<span class="line"><span>- 파트너: 현대차, GS칼텍스, 한국전력 제휴</span></span>
<span class="line"><span></span></span>
<span class="line"><span>연간 보고서 구성: \`content/annual-report-2023.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 대표 인사말 (1페이지)</span></span>
<span class="line"><span>   - 2023년 회고 + 2024년 비전</span></span>
<span class="line"><span>   - 진심이 느껴지는 톤 (관료적 문구 아닌)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 2023 At a Glance (숫자 강조 페이지)</span></span>
<span class="line"><span>   - 핵심 지표 6~8개 (큰 숫자 + 전년 대비)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>3. 사업 성과</span></span>
<span class="line"><span>   - 충전 인프라 확대 (180→500기, 지역별 분포)</span></span>
<span class="line"><span>   - 매출 성장 스토리 (어떻게 167% 성장했나)</span></span>
<span class="line"><span>   - 주요 파트너십 &amp; 의미</span></span>
<span class="line"><span>   - 기술 혁신 (초급속 충전기 자체 개발)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. ESG &amp; 사회적 가치</span></span>
<span class="line"><span>   - 탄소 절감 효과 (충전소 이용 → 내연기관 대체 환산)</span></span>
<span class="line"><span>   - 지역 사회 기여 (농어촌 충전 인프라)</span></span>
<span class="line"><span>   - 직원 복지 &amp; 다양성</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 팀 &amp; 문화</span></span>
<span class="line"><span>   - 조직 성장 (55→85명)</span></span>
<span class="line"><span>   - 핵심 인재 영입 사례</span></span>
<span class="line"><span>   - 사내 문화 하이라이트</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 재무 요약</span></span>
<span class="line"><span>   - 매출, 영업이익, 투자 유치</span></span>
<span class="line"><span>   - 비용 구조 (R&amp;D 비중 강조)</span></span>
<span class="line"><span>   - 간략한 BS/IS (스타트업 수준)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 2024년 전망</span></span>
<span class="line"><span>   - 목표: 충전소 1,200기, 매출 250억</span></span>
<span class="line"><span>   - 해외 진출 계획 (동남아)</span></span>
<span class="line"><span>   - 기술 로드맵</span></span>
<span class="line"><span></span></span>
<span class="line"><span>전체 톤: 투자자에겐 성장 확신, 고객에겐 신뢰, 직원에겐 자부심.</span></span>
<span class="line"><span>그래프/차트는 텍스트 기반 표로 대체.</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 대표 인사말의 진정성</li><li>[ ] At a Glance의 임팩트 있는 숫자 선별</li><li>[ ] 성장 스토리텔링 (단순 나열 아닌 서사)</li><li>[ ] ESG 섹션의 진정성 (그린워싱 아닌 실질)</li><li>[ ] 재무 요약의 투명성</li><li>[ ] 2024 전망의 야심+현실성 균형</li><li>[ ] 3개 독자(투자자/고객/직원) 모두를 고려한 톤</li></ul><hr><h2 id="cc-07-사내-교육-영상-대본" tabindex="-1">CC-07. 사내 교육 영상 대본 ⭐⭐ <a class="header-anchor" href="#cc-07-사내-교육-영상-대본" aria-label="Permalink to &quot;CC-07. 사내 교육 영상 대본 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-6" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-6" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>직원 교육용 영상의 대본 작성.</p><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>신입사원 대상 &quot;우리 제품 이해하기&quot; 교육 영상 대본을 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>서비스: &quot;커넥트HR&quot; — 기업용 인사관리 SaaS</span></span>
<span class="line"><span>영상 길이: 15분</span></span>
<span class="line"><span>형식: 화면 녹화(제품 시연) + 내레이션</span></span>
<span class="line"><span>대상: 개발팀 제외 전 직군 신입사원 (영업, CS, 마케팅, 경영지원)</span></span>
<span class="line"><span>목적: 제품을 직접 안 만드는 사람도 &quot;우리 뭐 파는 회사인지&quot; 정확히 이해</span></span>
<span class="line"><span></span></span>
<span class="line"><span>대본 구성:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`content/product-training-script.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   도입 (0:00~1:30)</span></span>
<span class="line"><span>   - &quot;여러분이 이 영상을 다 보면 고객 앞에서 자신 있게 설명할 수 있습니다&quot;</span></span>
<span class="line"><span>   - 커넥트HR이 뭔지 한 문장으로</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   우리 고객은 누구? (1:30~3:00)</span></span>
<span class="line"><span>   - 페르소나 2명 소개 (중소기업 HR팀장, 스타트업 대표)</span></span>
<span class="line"><span>   - 이 사람들이 뭘 힘들어하는지 (공감 유도)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   제품 시연 (3:00~10:00)</span></span>
<span class="line"><span>   - 핵심 기능 5가지를 시나리오로 시연</span></span>
<span class="line"><span>   - 시나리오: &quot;신입사원이 입사하는 날부터 첫 급여를 받을 때까지&quot;</span></span>
<span class="line"><span>   - 각 화면: 내레이션 + 화면 조작 지시 + 강조 포인트</span></span>
<span class="line"><span>   - 중간중간: &quot;이 기능 덕분에 고객이 뭘 안 해도 되는지&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   경쟁사와 뭐가 다른가? (10:00~12:00)</span></span>
<span class="line"><span>   - 비교 포인트 3가지 (기능 아닌 가치 차원)</span></span>
<span class="line"><span>   - &quot;고객이 물어볼 때 이렇게 답하세요&quot; 화법</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   자주 묻는 질문 (12:00~14:00)</span></span>
<span class="line"><span>   - &quot;가격이 어떻게 되나요?&quot; — 대답 가이드</span></span>
<span class="line"><span>   - &quot;데이터 이전이 어렵지 않나요?&quot; — 대답 가이드</span></span>
<span class="line"><span>   - &quot;보안은 안전한가요?&quot; — 대답 가이드</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   마무리 (14:00~15:00)</span></span>
<span class="line"><span>   - 핵심 정리 3가지</span></span>
<span class="line"><span>   - &quot;더 알고 싶으면 이 자료를 보세요&quot;</span></span>
<span class="line"><span>   - 퀴즈 안내 (교육 후 10문항 퀴즈)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`content/product-training-quiz.md\` — 교육 후 퀴즈 10문항</span></span>
<span class="line"><span>   - 핵심 내용 확인 (객관식 7 + OX 3)</span></span>
<span class="line"><span>   - 정답 및 해설</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 시나리오 기반 시연의 자연스러움</li><li>[ ] 비개발 직군에 맞는 설명 수준</li><li>[ ] 화면 조작 지시의 구체성 (촬영팀이 따라할 수 있는)</li><li>[ ] 경쟁사 비교를 &quot;가치&quot; 차원으로 전환</li><li>[ ] FAQ 대답 가이드의 실전 활용성</li><li>[ ] 15분에 맞는 분량</li><li>[ ] 퀴즈의 교육적 가치</li></ul><hr><h2 id="cc-08-사보-매거진-기사" tabindex="-1">CC-08. 사보/매거진 기사 ⭐⭐ <a class="header-anchor" href="#cc-08-사보-매거진-기사" aria-label="Permalink to &quot;CC-08. 사보/매거진 기사 :star::star:&quot;">​</a></h2><h3 id="시나리오-배경-7" tabindex="-1">시나리오 배경 <a class="header-anchor" href="#시나리오-배경-7" aria-label="Permalink to &quot;시나리오 배경&quot;">​</a></h3><p>사보(사내보) 또는 고객사 매거진에 실을 기사 형태의 콘텐츠.</p><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 3가지 유형의 사보 기사를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: 중견 건설사 &quot;한성건설&quot; (직원 1,200명)</span></span>
<span class="line"><span>사보: 격월 발행 &quot;한성 뉴스&quot; (PDF + 인트라넷)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>기사 1: 인물 인터뷰 — &quot;현장에서 만난 사람들&quot;</span></span>
<span class="line"><span>- 대상: 김동현 현장소장 (25년차, 최근 랜드마크 빌딩 준공)</span></span>
<span class="line"><span>- 분량: A4 2페이지</span></span>
<span class="line"><span>- 구성: 인트로(현장 묘사) → Q&amp;A 형식 → 에피소드 2개 → 후배에게 한마디</span></span>
<span class="line"><span>- 질문: 25년간 가장 기억에 남는 현장, 위기 순간, 건설업의 미래, </span></span>
<span class="line"><span>  후배들에게 조언, 퇴근 후 취미</span></span>
<span class="line"><span>- 톤: 인간적이고 따뜻한, 현장의 생동감</span></span>
<span class="line"><span></span></span>
<span class="line"><span>기사 2: 프로젝트 르포 — &quot;○○동 재개발 프로젝트의 365일&quot;</span></span>
<span class="line"><span>- 대상: 착공~준공 1년간의 이야기</span></span>
<span class="line"><span>- 분량: A4 3페이지</span></span>
<span class="line"><span>- 구성: 착공식 장면 → 난관(기후, 민원) → 해결 과정 → 준공 감동 → 입주민 반응</span></span>
<span class="line"><span>- 톤: 다큐멘터리처럼 시간 순서대로, 현장감 있게</span></span>
<span class="line"><span></span></span>
<span class="line"><span>기사 3: 칼럼 — &quot;ESG가 건설업을 바꿀 수 있을까&quot;</span></span>
<span class="line"><span>- 필자: 경영기획팀 이사 (가상)</span></span>
<span class="line"><span>- 분량: A4 1.5페이지</span></span>
<span class="line"><span>- 구성: 문제 제기 → 건설업 ESG 현황 → 우리 회사 사례 → 미래 전망</span></span>
<span class="line"><span>- 톤: 전문적이지만 읽기 쉬운, 사내 오피니언 리더의 시각</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`content/company-magazine-articles.md\`</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 인터뷰: Q&amp;A의 자연스러운 대화 흐름</li><li>[ ] 인터뷰: 인간적 에피소드의 생동감</li><li>[ ] 르포: 시간 순서에 따른 서사 구조</li><li>[ ] 르포: 현장감 있는 묘사 (날씨, 소리, 감정)</li><li>[ ] 칼럼: 전문적 시각 + 자사 사례의 자연스러운 연결</li><li>[ ] 3개 기사의 톤 차별화</li><li>[ ] 건설업 도메인 용어의 적절한 사용</li></ul>`,66)])])}const q=s(e,[["render",i]]);export{d as __pageData,q as default};
